const http = require('http');
const https = require('https');
const url = require('url');
const fs = require('fs');
const path = require('path');
const { VM, VMScript } = require('vm2');

// ============================================================
// SECURE API Gateway with Plugin System
// ============================================================
// SECURITY NOTES:
// - We do NOT use eval() or raw require() for plugin loading
// - Plugins run in a sandboxed VM (vm2) with limited capabilities
// - Plugin code is validated before execution
// - File system access is restricted to a designated plugins directory
// - Environment variable plugin code is sandboxed equally
