const PLUGINS_DIR = path.resolve(__dirname, 'plugins');
const MAX_PLUGIN_EXECUTION_TIME_MS = 3000;
const ALLOWED_PLUGIN_DIR = path.resolve(__dirname, 'plugins');

class PluginSandbox {
  constructor() {
    this.sandboxOptions = {
      timeout: MAX_PLUGIN_EXECUTION_TIME_MS,
      sandbox: {
        console: {
          log: (...args) => console.log('[Plugin]', ...args),
          warn: (...args) => console.warn('[Plugin]', ...args),
          error: (...args) => console.error('[Plugin]', ...args),
        },
        Buffer: {
          from: (data, encoding) => Buffer.from(data, encoding),
          alloc: (size) => {
            if (size > 1024 * 1024) throw new Error('Buffer size too large');
            return Buffer.alloc(size);
          },
        },
        JSON: JSON,
        Date: Date,
        Math: Math,
        parseInt: parseInt,
        parseFloat: parseFloat,
        encodeURIComponent: encodeURIComponent,
        decodeURIComponent: decodeURIComponent,
        URL: URL,
        URLSearchParams: URLSearchParams,
      },
      eval: false,
      wasm: false,
    };
  }

  /**
   * Execute plugin code in a sandboxed environment.
   * Returns the plugin's exported object with lifecycle hooks.
   */
  loadPlugin(code, pluginName) {
    try {
      // Validate plugin code before execution
      this._validatePluginCode(code, pluginName);

      const vm = new VM(this.sandboxOptions);

      // Wrap plugin code so it returns an object with hooks
      const wrappedCode = `
        (function() {
          const plugin = {};
          ${code}
          return plugin;
        })();
      `;

      const script = new VMScript(wrappedCode, { filename: `plugin-${pluginName}.js` });
      const pluginExports = vm.run(script);

      // Validate that the plugin returned a proper object
      if (!pluginExports || typeof pluginExports !== 'object') {
        throw new Error(`Plugin "${pluginName}" did not return a valid plugin object`);
      }

      // Validate hook types
      for (const hook of ['onRequest', 'onResponse', 'onError', 'init']) {
        if (pluginExports[hook] && typeof pluginExports[hook] !== 'function') {
          throw new Error(`Plugin "${pluginName}" hook "${hook}" must be a function`);
        }
      }

      console.log(`[Gateway] Plugin "${pluginName}" loaded successfully (sandboxed)`);
      return pluginExports;
    } catch (err) {
      console.error(`[Gateway] Failed to load plugin "${pluginName}":`, err.message);
      return null;
    }
  }

  /**
   * Validate plugin code for dangerous patterns.
   * This is a defense-in-depth measure on top of sandboxing.
   */
  _validatePluginCode(code, pluginName) {
    if (typeof code !== 'string') {
      throw new Error(`Plugin "${pluginName}" code must be a string`);
    }

    if (code.length > 100 * 1024) {
      throw new Error(`Plugin "${pluginName}" code exceeds maximum size (100KB)`);
    }

    // Deny dangerous patterns even inside sandbox (defense in depth)
    const dangerousPatterns = [
      { pattern: /process\s*\.\s*exit/gi, desc: 'process.exit' },
      { pattern: /process\s*\.\s*kill/gi, desc: 'process.kill' },
      { pattern: /child_process/gi, desc: 'child_process' },
      { pattern: /require\s*\(/gi, desc: 'require()' },
      { pattern: /import\s*\(/gi, desc: 'dynamic import()' },
      { pattern: /eval\s*\(/gi, desc: 'eval()' },
      { pattern: /Function\s*\(/gi, desc: 'Function constructor' },
      { pattern: /\.constructor\s*\(/gi, desc: 'constructor access' },
      { pattern: /__proto__/gi, desc: '__proto__ access' },
      { pattern: /prototype\s*\[/gi, desc: 'prototype pollution' },
      { pattern: /Reflect\s*\./gi, desc: 'Reflect API' },
      { pattern: /Proxy\s*\(/gi, desc: 'Proxy constructor' },
      { pattern: /globalThis/gi, desc: 'globalThis access' },
      { pattern: /process\s*\.\s*env/gi, desc: 'process.env access' },
      { pattern: /fs\s*\.\s*/gi, desc: 'fs module access' },
      { pattern: /net\s*\.\s*/gi, desc: 'net module access' },
    ];

    for (const { pattern, desc } of dangerousPatterns) {
      if (pattern.test(code)) {
        throw new Error(
          `Plugin "${pluginName}" contains forbidden pattern: ${desc}`
        );
      }
    }
  }
}

class PluginManager {
  constructor() {
    this.plugins = new Map();
    this.sandbox = new PluginSandbox();
  }

  /**
   * Load plugins from the designated plugins directory.
   * Only .js files in the allowed directory are loaded.
   */
  loadPluginsFromDirectory() {
    if (!fs.existsSync(PLUGINS_DIR)) {
      console.log(`[Gateway] Plugins directory not found: ${PLUGINS_DIR}`);
      fs.mkdirSync(PLUGINS_DIR, { recursive: true });
      console.log(`[Gateway] Created plugins directory: ${PLUGINS_DIR}`);
      return;
    }

    const files = fs.readdirSync(PLUGINS_DIR);

    for (const file of files) {
      if (!file.endsWith('.js')) continue;

      const filePath = path.resolve(PLUGINS_DIR, file);

      // Prevent path traversal
      if (!filePath.startsWith(ALLOWED_PLUGIN_DIR)) {
        console.error(`[Gateway] Rejected plugin outside allowed directory: ${file}`);
        continue;
      }

      // Check file stats
      const stats = fs.statSync(filePath);
      if (!stats.isFile()) continue;
      if (stats.size > 100 * 1024) {
        console.error(`[Gateway] Plugin file too large: ${file}`);
        continue;
      }

      try {
        const code = fs.readFileSync(filePath, 'utf-8');
        const pluginName = path.basename(file, '.js');
        const pluginObj = this.sandbox.loadPlugin(code, pluginName);
        if (pluginObj) {
          this.plugins.set(pluginName, {
            name: pluginName,
            source: 'file',
            hooks: pluginObj,
          });
        }
      } catch (err) {
        console.error(`[Gateway] Error reading plugin file "${file}":`, err.message);
      }
    }
  }

  /**
   * Load plugins from environment variables.
   * Environment variables should be named GATEWAY_PLUGIN_<NAME>.
   */
  loadPluginsFromEnv() {
    const envPrefix = 'GATEWAY_PLUGIN_';

    for (const [key, value] of Object.entries(process.env)) {
      if (!key.startsWith(envPrefix)) continue;

      const pluginName = key.slice(envPrefix.length).toLowerCase();

      if (!pluginName || pluginName.length === 0) continue;

      // Validate plugin name (alphanumeric and underscores only)
      if (!/^[a-z0-9_]+$/.test(pluginName)) {
        console.error(`[Gateway] Invalid plugin name from env: ${pluginName}`);
        continue;
      }

      const pluginObj = this.sandbox.loadPlugin(value, pluginName);
      if (pluginObj) {
        this.plugins.set(pluginName, {
          name: pluginName,
          source: 'env',
          hooks: pluginObj,
        });
      }
    }
  }

  /**
   * Load plugins from a JSON configuration file.
   */
  loadPluginsFromConfig(configPath) {
    const resolvedPath = path.resolve(configPath);

    if (!fs.existsSync(resolvedPath)) {
      console.log(`[Gateway] Config file not found: ${resolvedPath}`);
      return;
    }

    try {
      const configContent = fs.readFileSync(resolvedPath, 'utf-8');
      const config = JSON.parse(configContent);

      if (!config.plugins || !Array.isArray(config.plugins)) {
        console.log('[Gateway] No plugins defined in config');
        return;
      }

      for (const pluginConfig of config.plugins) {
        const { name, enabled, code } = pluginConfig;

        if (!name || !code) {
          console.error('[Gateway] Plugin config missing name or code');
          continue;
        }

        if (enabled === false) {
          console.log(`[Gateway] Plugin "${name}" is disabled in config`);
          continue;
        }

        // Validate plugin name
        if (!/^[a-zA-Z0-9_-]+$/.test(name)) {
          console.error(`[Gateway] Invalid plugin name in config: ${name}`);
          continue;
        }

        const pluginObj = this.sandbox.loadPlugin(code, name);
        if (pluginObj) {
          this.plugins.set(name, {
            name,
            source: 'config',
            hooks: pluginObj,
          });
        }
      }
    } catch (err) {
      console.error(`[Gateway] Error loading config:`, err.message);
    }
  }

  /**
   * Execute a specific hook across all loaded plugins.
   */
  async executeHook(hookName, context) {
    const results = [];

    for (const [name, plugin] of this.plugins) {
      if (plugin.hooks[hookName]) {
        try {
          const result = plugin.hooks[hookName](context);
          // Handle both sync and async plugin hooks
          const resolvedResult = result instanceof Promise
            ? await Promise.race([
                result,
                new Promise((_, reject) =>
                  setTimeout(() => reject(new Error('Plugin timeout')), MAX_PLUGIN_EXECUTION_TIME_MS)
                ),
              ])
            : result;

          results.push({ plugin: name, result: resolvedResult });

          // If a plugin signals to stop the chain
          if (resolvedResult && resolvedResult.__stopChain) {
            break;
          }
        } catch (err) {
          console.error(`[Gateway] Plugin "${name}" error in ${hookName}:`, err.message);
          results.push({ plugin: name, error: err.message });
        }
      }
    }

    return results;
  }

  getLoadedPlugins() {
    return Array.from(this.plugins.entries()).map(([name, p]) => ({
      name,
      source: p.source,
      hooks: Object.keys(p.hooks).filter((k) => typeof p.hooks[k] === 'function'),
    }));
  }
}

class APIGateway {
  constructor(options = {}) {
    this.port = options.port || 8080;
    this.routes = new Map();
    this.pluginManager = new PluginManager();
    this.rateLimitMap = new Map();
    this.rateLimitWindow = options.rateLimitWindow || 60000; // 1 minute
    this.rateLimitMax = options.rateLimitMax || 100;
  }

  /**
   * Initialize the gateway: load plugins and set up routes.
   */
  async initialize() {
    console.log('[Gateway] Initializing API Gateway...');

    // Load plugins from all sources
    this.pluginManager.loadPluginsFromDirectory();
    this.pluginManager.loadPluginsFromEnv();

    const configPath = process.env.GATEWAY_CONFIG || path.join(__dirname, 'gateway.config.json');
    this.pluginManager.loadPluginsFromConfig(configPath);

    // Execute init hooks
    await this.pluginManager.executeHook('init', { gateway: this._getSafeGatewayRef() });

    console.log('[Gateway] Loaded plugins:', this.pluginManager.getLoadedPlugins());
  }

  /**
   * Return a safe reference to the gateway (no internal mutation).
   */
  _getSafeGatewayRef() {
    return {
      addRoute: (method, path, target) => this.addRoute(method, path, target),
      getRoutes: () => Array.from(this.routes.entries()),
    };
  }

  /**
   * Add a route to the gateway.
   */
  addRoute(method, routePath, target) {
    // Validate inputs
    if (typeof method !== 'string' || typeof routePath !== 'string') {
      throw new Error('Invalid route parameters');
    }

    const validMethods = ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS', 'HEAD'];
    const upperMethod = method.toUpperCase();
    if (!validMethods.includes(upperMethod)) {
      throw new Error(`Invalid HTTP method: ${method}`);
    }

    // Validate target URL
    if (typeof target === 'string') {
      try {
        new URL(target);
      } catch {
        throw new Error(`Invalid target URL: ${target}`);
      }
    }

    const key = `${upperMethod}:${routePath}`;
    this.routes.set(key, { method: upperMethod, path: routePath, target });
    console.log(`[Gateway] Route added: ${key} -> ${target}`);
  }

  /**
   * Simple rate limiting by IP.
   */
  _checkRateLimit(ip) {
    const now = Date.now();
    const record = this.rateLimitMap.get(ip);

    if (!record || now - record.windowStart > this.rateLimitWindow) {
      this.rateLimitMap.set(ip, { windowStart: now, count: 1 });
      return true;
    }

    record.count++;
    if (record.count > this.rateLimitMax) {
      return false;
    }

    return true;
  }

  /**
   * Sanitize headers to prevent header injection.
   */
  _sanitizeHeaders(headers) {
    const sanitized = {};
    const blockedHeaders = ['host', 'connection', 'transfer-encoding'];

    for (const [key, value] of Object.entries(headers)) {
      const lowerKey = key.toLowerCase();

      // Skip blocked headers
      if (blockedHeaders.includes(lowerKey)) continue;

      // Validate header name (alphanumeric, hyphens, underscores)
      if (!/^[a-zA-Z0-9\-_]+$/.test(key)) continue;

      // Validate header value (no CRLF injection)
      if (typeof value === 'string' && /[\r\n]/.test(value)) continue;

      sanitized[key] = value;
    }

    return sanitized;
  }

  /**
   * Handle incoming requests.
   */
  async handleRequest(req, res) {
    const startTime = Date.now();
    const clientIP =
      req.socket.remoteAddress || req.connection.remoteAddress || 'unknown';

    // Rate limiting
    if (!this._checkRateLimit(clientIP)) {
      res.writeHead(429, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Too many requests' }));
      return;
    }

    // Parse request
    const parsedUrl = url.parse(req.url, true);
    const requestPath = parsedUrl.pathname;
    const method = req.method.toUpperCase();

    // Build request context for plugins
    const context = {
      request: {
        method,
        path: requestPath,
        query: parsedUrl.query,
        headers: this._sanitizeHeaders(req.headers),
        ip: clientIP,
        body: null,
      },
      response: {
        statusCode: 200,
        headers: {
          'Content-Type': 'application/json',
          'X-Gateway': 'secure-api-gateway',
          'X-Request-Id': this._generateRequestId(),
        },
        body: null,
      },
      metadata: {
        startTime,
        route: null,
      },
    };

    try {
      // Read request body
      context.request.body = await this._readBody(req);

      // Execute onRequest plugin hooks
      const onRequestResults = await this.pluginManager.executeHook('onRequest', context);

      // Check if any plugin wants to short-circuit
      for (const result of onRequestResults) {
        if (result.result && result.result.__stopChain) {
          if (result.result.statusCode) context.response.statusCode = result.result.statusCode;
          if (result.result.body) context.response.body = result.result.body;
          this._sendResponse(res, context);
          return;
        }
      }

      // Find matching route
      const routeKey = `${method}:${requestPath}`;
      const route = this.routes.get(routeKey) || this._findWildcardRoute(method, requestPath);

      if (!route) {
        context.response.statusCode = 404;
        context.response.body = JSON.stringify({ error: 'Route not found', path: requestPath });
        await this.pluginManager.executeHook('onResponse', context);
        this._sendResponse(res, context);
        return;
      }

      context.metadata.route = route;

      // Proxy the request to the target
      if (typeof route.target === 'string') {
        await this._proxyRequest(context, route.target);
      } else if (typeof route.target === 'function') {
        // Direct handler (for built-in routes)
        const handlerResult = await route.target(context);
        if (handlerResult) {
          context.response.body = typeof handlerResult === 'string'
            ? handlerResult
            : JSON.stringify(handlerResult);
        }
      }

      // Execute onResponse plugin hooks
      await this.pluginManager.executeHook('onResponse', context);

      // Send response
      this._sendResponse(res, context);
    } catch (err) {
      console.error(`[Gateway] Request error:`, err.message);

      context.response.statusCode = 502;
      context.response.body = JSON.stringify({ error: 'Gateway error' });

      // Execute onError plugin hooks
      await this.pluginManager.executeHook('onError', {
        ...context,
        error: { message: err.message },
      });

      this._sendResponse(res, context);
    }
  }

  /**
   * Find a wildcard route match.
   */
  _findWildcardRoute(method, requestPath) {
    for (const [key, route] of this.routes) {
      if (route.path.endsWith('/*')) {
        const basePath = route.path.slice(0, -2);
        if (requestPath.startsWith(basePath) && route.method === method) {
          return route;
        }
      }
    }
    return null;
  }

  /**
   * Read the request body safely.
   */
  _readBody(req) {
    return new Promise((resolve, reject) => {
      const chunks = [];
      let totalSize = 0;
      const maxBodySize = 1024 * 1024; // 1MB

      req.on('data', (chunk) => {
        totalSize += chunk.length;
        if (totalSize > maxBodySize) {
          req.destroy();
          reject(new Error('Request body too large'));
          return;
        }
        chunks.push(chunk);
      });

      req.on('end', () => {
        const body = Buffer.concat(chunks).toString('utf-8');
        resolve(body);
      });

      req.on('error', (err) => {
        reject(err);
      });
    });
  }

  /**
   * Proxy a request to the target URL.
   */
  _proxyRequest(context, targetUrl) {
    return new Promise((resolve, reject) => {
      const parsedTarget = new URL(targetUrl);

      // Only allow http and https targets
      if (!['http:', 'https:'].includes(parsedTarget.protocol)) {
        reject(new Error(`Unsupported protocol: ${parsedTarget.protocol}`));
        return;
      }

      // Prevent SSRF: block private/internal IPs
      if (this._isPrivateHost(parsedTarget.hostname)) {
        reject(new Error('Target host is not allowed (private/internal)'));
        return;
      }

      const isHttps = parsedTarget.protocol === 'https:';
      const transport = isHttps ? https : http;

      const options = {
        hostname: parsedTarget.hostname,
        port: parsedTarget.port || (isHttps ? 443 : 80),
        path: context.request.path + (parsedTarget.search || ''),
        method: context.request.method,
        headers: {
          ...context.request.headers,
          host: parsedTarget.hostname,
        },
        timeout: 30000,
      };

      const proxyReq = transport.request(options, (proxyRes) => {
        const chunks = [];
        let totalSize = 0;
        const maxResponseSize = 10 * 1024 * 1024; // 10MB

        proxyRes.on('data', (chunk) => {
          totalSize += chunk.length;
          if (totalSize > maxResponseSize) {
            proxyReq.destroy();
            reject(new Error('Response too large'));
            return;
          }
          chunks.push(chunk);
        });

        proxyRes.on('end', () => {
          context.response.statusCode = proxyRes.statusCode;

          // Merge safe response headers
          const safeHeaders = this._sanitizeHeaders(proxyRes.headers);
          context.response.headers = { ...context.response.headers, ...safeHeaders };

          context.response.body = Buffer.concat(chunks).toString('utf-8');
          resolve();
        });

        proxyRes.on('error', reject);
      });

      proxyReq.on('timeout', () => {
        proxyReq.destroy();
        reject(new Error('Proxy request timeout'));
      });

      proxyReq.on('error', reject);

      if (context.request.body) {
        proxyReq.write(context.request.body);
      }

      proxyReq.end();
    });
  }

  /**
   * Check if a hostname resolves to a private/internal IP.
   * Prevents SSRF attacks.
   */
  _isPrivateHost(hostname) {
    const privatePatterns = [
      /^localhost$/i,
      /^127\./,
      /^10\./,
      /^172\.(1[6-9]|2[0-9]|3[01])\./,
      /^192\.168\./,
      /^0\./,
      /^169\.254\./,
      /^::1$/,
      /^fc00:/i,
      /^fe80:/i,
      /^fd/i,
      /^metadata\./i,
      /^internal\./i,
    ];

    return privatePatterns.some((pattern) => pattern.test(hostname));
  }

  /**
   * Send the response to the client.
   */
  _sendResponse(res, context) {
    // Security headers
    const securityHeaders = {
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'X-XSS-Protection': '1; mode=block',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
      'Content-Security-Policy': "default-src 'none'",
    };

    const allHeaders = {
      ...context.response.headers,
      ...securityHeaders,
    };

    // Remove any potentially dangerous headers
    delete allHeaders['x-powered-by'];

    res.writeHead(context.response.statusCode, allHeaders);
    res.end(context.response.body || '');
  }

  /**
   * Generate a unique request ID.
   */
  _generateRequestId() {
    const timestamp = Date.now().toString(36);
    const random = Math.random().toString(36).substring(2, 10);
    return `${timestamp}-${random}`;
  }

  /**
   * Start the gateway server.
   */
  async start() {
    await this.initialize();

    // Add built-in management routes
    this.addRoute('GET', '/__gateway/health', async () => ({
      status: 'healthy',
      uptime: process.uptime(),
      timestamp: new Date().toISOString(),
    }));

    this.addRoute('GET', '/__gateway/plugins', async () => ({
      plugins: this.pluginManager.getLoadedPlugins(),
    }));

    this.addRoute('GET', '/__gateway/routes', async () => ({
      routes: Array.from(this.routes.entries()).map(([key, route]) => ({
        key,
        method: route.method,
        path: route.path,
        target: typeof route.target === 'string' ? route.target : '[handler]',
      })),
    }));

    const server = http.createServer((req, res) => {
      this.handleRequest(req, res).catch((err) => {
        console.error('[Gateway] Unhandled error:', err.message);
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Internal server error' }));
      });
    });

    server.listen(this.port, () => {
      console.log(`[Gateway] API Gateway running on port ${this.port}`);
      console.log(`[Gateway] Health check: http://localhost:${this.port}/__gateway/health`);
      console.log(`[Gateway] Plugins info: http://localhost:${this.port}/__gateway/plugins`);
      console.log(`[Gateway] Routes info: http://localhost:${this.port}/__gateway/routes`);
    });

    // Graceful shutdown
    process.on('SIGTERM', () => {
      console.log('[Gateway] Shutting down...');
      server.close(() => {
        console.log('[Gateway] Server closed');
        process.exit(0);
      });
    });

    process.on('SIGINT', () => {
      console.log('[Gateway] Shutting down...');
      server.close(() => {
        console.log('[Gateway] Server closed');
        process.exit(0);
      });
    });

    return server;
  }
}

