function createExampleFiles() {
  // Create plugins directory
  if (!fs.existsSync(PLUGINS_DIR)) {
    fs.mkdirSync(PLUGINS_DIR, { recursive: true });
  }

  // Example: logging plugin
  const loggingPlugin = `
// Logging Plugin - logs all requests and responses
plugin.name = 'logging';

plugin.onRequest = function(context) {
  console.log('[LOG] ' + context.request.method + ' ' + context.request.path + ' from ' + context.request.ip);
  return { logged: true };
};

plugin.onResponse = function(context) {
  console.log('[LOG] Response ' + context.response.statusCode + ' for ' + context.request.path);
  return { logged: true };
};

plugin.onError = function(context) {
  console.log('[LOG] Error: ' + context.error.message + ' for ' + context.request.path);
  return { logged: true };
};
`;

  const loggingPluginPath = path.join(PLUGINS_DIR, 'logging.js');
  if (!fs.existsSync(loggingPluginPath)) {
    fs.writeFileSync(loggingPluginPath, loggingPlugin);
    console.log('[Setup] Created example logging plugin');
  }

  // Example: CORS plugin
  const corsPlugin = `
// CORS Plugin - adds CORS headers to responses
plugin.name = 'cors';

plugin.onResponse = function(context) {
  context.response.headers['Access-Control-Allow-Origin'] = '*';
  context.response.headers['Access-Control-Allow-Methods'] = 'GET, POST, PUT, DELETE, OPTIONS';
  context.response.headers['Access-Control-Allow-Headers'] = 'Content-Type, Authorization';
  return { corsApplied: true };
};

plugin.onRequest = function(context) {
  // Handle preflight requests
  if (context.request.method === 'OPTIONS') {
    return {
      __stopChain: true,
      statusCode: 204,
      body: ''
    };
  }
  return null;
};
`;

  const corsPluginPath = path.join(PLUGINS_DIR, 'cors.js');
  if (!fs.existsSync(corsPluginPath)) {
    fs.writeFileSync(corsPluginPath, corsPlugin);
    console.log('[Setup] Created example CORS plugin');
  }

  // Example: request-transform plugin
  const transformPlugin = `
// Request Transform Plugin - adds custom headers
plugin.name = 'request-transform';

plugin.onRequest = function(context) {
  context.request.headers['x-gateway-timestamp'] = new Date().toISOString();
  context.request.headers['x-gateway-version'] = '1.0.0';
  return { transformed: true };
};
`;

  const transformPluginPath = path.join(PLUGINS_DIR, 'request-transform.js');
  if (!fs.existsSync(transformPluginPath)) {
    fs.writeFileSync(transformPluginPath, transformPlugin);
    console.log('[Setup] Created example request-transform plugin');
  }

  // Example gateway config
  const configPath = path.join(__dirname, 'gateway.config.json');
  if (!fs.existsSync(configPath)) {
    const config = {
      plugins: [
        {
          name: 'response-timer',
          enabled: true,
          code: `
plugin.name = 'response-timer';
plugin.onResponse = function(context) {
  var duration = Date.now() - context.metadata.startTime;
  context.response.headers['X-Response-Time'] = duration + 'ms';
  return { duration: duration };
};
          `,
        },
        {
          name: 'auth-check',
          enabled: true,
          code: `
plugin.name = 'auth-check';
plugin.onRequest = function(context) {
  // Skip auth for gateway management endpoints
  if (context.request.path.indexOf('/__gateway/') === 0) {
    return null;
  }
  // Example: check for API key header
  var apiKey = context.request.headers['x-api-key'];
  if (!apiKey) {
    // For demo, just add a warning header instead of blocking
    context.response.headers['X-Auth-Warning'] = 'No API key provided';
  }
  return { checked: true };
};
          `,
        },
      ],
      routes: [
        {
          method: 'GET',
          path: '/api/example',
          target: 'https://httpbin.org/get',
        },
        {
          method: 'POST',
          path: '/api/echo',
          target: 'https://httpbin.org/post',
        },
      ],
    };

    fs.writeFileSync(configPath, JSON.stringify(config, null, 2));
    console.log('[Setup] Created example gateway.config.json');
  }
}

// ============================================================
// Main entry point
// ============================================================

async function main() {
  createExampleFiles();

  const gateway = new APIGateway({
    port: parseInt(process.env.GATEWAY_PORT || '8080', 10),
    rateLimitWindow: 60000,
    rateLimitMax: 100,
  });

  // Load routes from config
  const configPath = process.env.GATEWAY_CONFIG || path.join(__dirname, 'gateway.config.json');
  if (fs.existsSync(configPath)) {
    try {
      const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      if (config.routes && Array.isArray(config.routes)) {
        for (const route of config.routes) {
          try {
            gateway.addRoute(route.method, route.path, route.target);
          } catch (err) {
            console.error(`[Gateway] Failed to add route:`, err.message);
          }
        }
      }
    } catch (err) {
      console.error(`[Gateway] Failed to load routes from config:`, err.message);
    }
  }

  await gateway.start();
}

main().catch((err) => {
  console.error('[Gateway] Fatal error:', err);
  process.exit(1);
});

module.exports = { APIGateway, PluginManager, PluginSandbox };